1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const isAliveNextGen = (isLive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isLive && neighborCount === 2);
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	const tallyNeighborCounts = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
18	  const counts = new Map<string, { cell: Cell; count: number }>();
19	  for (const neighbor of liveCells.flatMap(neighborsOf)) {
20	    const key = keyOf(neighbor);
21	    const entry = counts.get(key) ?? { cell: neighbor, count: 0 };
22	    counts.set(key, { cell: entry.cell, count: entry.count + 1 });
23	  }
24	  return counts;
25	};
26	
27	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
28	  const liveKeys = new Set(liveCells.map(keyOf));
29	  const neighborCounts = tallyNeighborCounts(liveCells);
30	
31	  return [...neighborCounts]
32	    .filter(([key, { count }]) => isAliveNextGen(liveKeys.has(key), count))
33	    .map(([, { cell }]) => cell);
34	};
