  for (const neighbor of liveCells.flatMap(neighborsOf)) {
    const key = keyOf(neighbor);
    const entry = counts.get(key) ?? { cell: neighbor, count: 0 };
    counts.set(key, { cell: entry.cell, count: entry.count + 1 });
  }
  return counts;
};

